CREATE TABLE roles (id SERIAL PRIMARY KEY, code TEXT NOT NULL UNIQUE, name TEXT NOT NULL, description TEXT NOT NULL);
CREATE TABLE users (id SERIAL PRIMARY KEY, name TEXT NOT NULL, username TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, role_id INTEGER NOT NULL REFERENCES roles(id) ON DELETE RESTRICT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE sessions (id SERIAL PRIMARY KEY, token_hash TEXT NOT NULL UNIQUE, user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE, expires_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX sessions_user_idx ON sessions(user_id);

CREATE TABLE mods (id SERIAL PRIMARY KEY, slug TEXT NOT NULL UNIQUE, title TEXT NOT NULL, short_description TEXT NOT NULL, full_description TEXT NOT NULL, server_purpose TEXT NOT NULL DEFAULT '', mechanics TEXT NOT NULL DEFAULT '', progression TEXT NOT NULL DEFAULT '', practical_notes TEXT NOT NULL DEFAULT '', category TEXT NOT NULL, cover_image TEXT, gallery TEXT NOT NULL DEFAULT '[]', featured BOOLEAN NOT NULL DEFAULT FALSE, status TEXT NOT NULL DEFAULT 'draft', sort_order INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX mods_status_idx ON mods(status);
CREATE TABLE items (id SERIAL PRIMARY KEY, mod_id INTEGER NOT NULL REFERENCES mods(id) ON DELETE CASCADE, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL, summary TEXT NOT NULL, description TEXT NOT NULL, function_description TEXT NOT NULL DEFAULT '', requirements TEXT NOT NULL DEFAULT '', durability INTEGER, stats TEXT NOT NULL DEFAULT '{}', how_to_obtain TEXT NOT NULL DEFAULT '', uses TEXT NOT NULL DEFAULT '', tips TEXT NOT NULL DEFAULT '', image TEXT, gallery TEXT NOT NULL DEFAULT '[]', status TEXT NOT NULL DEFAULT 'draft', sort_order INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX items_mod_idx ON items(mod_id); CREATE INDEX items_status_idx ON items(status);
CREATE TABLE crafting_recipes (id SERIAL PRIMARY KEY, item_id INTEGER NOT NULL REFERENCES items(id) ON DELETE CASCADE, title TEXT NOT NULL, station TEXT NOT NULL, inputs TEXT NOT NULL DEFAULT '[]', output_name TEXT NOT NULL, output_quantity INTEGER NOT NULL DEFAULT 1, notes TEXT NOT NULL DEFAULT '', image TEXT, status TEXT NOT NULL DEFAULT 'draft', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX recipes_item_idx ON crafting_recipes(item_id);
CREATE TABLE tags (id SERIAL PRIMARY KEY, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL);
CREATE TABLE mod_tags (mod_id INTEGER NOT NULL REFERENCES mods(id) ON DELETE CASCADE, tag_id INTEGER NOT NULL REFERENCES tags(id) ON DELETE CASCADE, PRIMARY KEY (mod_id, tag_id));
CREATE TABLE item_tags (item_id INTEGER NOT NULL REFERENCES items(id) ON DELETE CASCADE, tag_id INTEGER NOT NULL REFERENCES tags(id) ON DELETE CASCADE, PRIMARY KEY (item_id, tag_id));
CREATE TABLE item_relations (item_id INTEGER NOT NULL REFERENCES items(id) ON DELETE CASCADE, related_item_id INTEGER NOT NULL REFERENCES items(id) ON DELETE CASCADE, PRIMARY KEY (item_id, related_item_id));
CREATE TABLE faq_entries (id SERIAL PRIMARY KEY, question TEXT NOT NULL, answer TEXT NOT NULL, category TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'draft', sort_order INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX faq_status_idx ON faq_entries(status);
CREATE TABLE installation_sections (id SERIAL PRIMARY KEY, title TEXT NOT NULL, intro TEXT NOT NULL DEFAULT '', body TEXT NOT NULL DEFAULT '', steps TEXT NOT NULL DEFAULT '[]', icon TEXT NOT NULL DEFAULT 'compass', status TEXT NOT NULL DEFAULT 'draft', sort_order INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX installation_status_idx ON installation_sections(status);
CREATE TABLE media_assets (id SERIAL PRIMARY KEY, title TEXT NOT NULL, url TEXT NOT NULL UNIQUE, alt_text TEXT NOT NULL, source_type TEXT NOT NULL DEFAULT 'external', mime_type TEXT, created_by_id INTEGER REFERENCES users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
